import{_ as i,o as e,c as t,ae as a}from"./chunks/framework.BGHOrOyn.js";const n="/gitbook-personnal-docs/assets/image%20(1)%20(1)%20(1).Ci3zBu39.png",p="/gitbook-personnal-docs/assets/image%20(2)%20(1).CKTkspr3.png",o="/gitbook-personnal-docs/assets/image%20(1)%20(1).CzrR8Xob.png",k=JSON.parse('{"title":"Online Resize Ubuntu/Debian Disk","description":"","frontmatter":{},"headers":[],"relativePath":"snippets-and-scripts/online-resize-ubuntu-debian-disk.md","filePath":"snippets-and-scripts/online-resize-ubuntu-debian-disk.md"}'),l={name:"snippets-and-scripts/online-resize-ubuntu-debian-disk.md"};function d(r,s,c,u,h,g){return e(),t("div",null,[...s[0]||(s[0]=[a('<h1 id="online-resize-ubuntu-debian-disk" tabindex="-1">Online Resize Ubuntu/Debian Disk <a class="header-anchor" href="#online-resize-ubuntu-debian-disk" aria-label="Permalink to &quot;Online Resize Ubuntu/Debian Disk&quot;">​</a></h1><p>Start by installing cloud-utils. This contains the growpart tool.</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sudo apt-get install -y cloud-utils</span></span></code></pre></div><figure><img src="'+n+`" alt=""><figcaption><p>The root partition is 32 GB but the device itself is 64GB. I intend to resize the root partition (/dev/sda2) </p></figcaption></figure><p>Run growpart</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sudo growpart /dev/sda 2</span></span></code></pre></div><p>The first parameter is the device you want to resize, and the second is the partition. Below is the output:</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">devin@postgres-replica:~$ sudo growpart /dev/sda 2</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CHANGED: partition=2 start=4096 old: size=67102720 end=67106816 new: size=134213599 end=134217695</span></span></code></pre></div><p>And then:</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sudo resize2fs /dev/sda2</span></span></code></pre></div><figure><img src="`+p+'" alt=""><figcaption></figcaption></figure><figure><img src="'+o+'" alt=""><figcaption><p>Success</p></figcaption></figure>',12)])])}const m=i(l,[["render",d]]);export{k as __pageData,m as default};
